create table balance_ledger (created_at timestamp(6) with time zone not null, delta_minor bigint not null, currency_code uuid not null, group_id uuid not null, id uuid not null, source_id uuid not null, user_id uuid not null, source_type varchar(20) not null check (source_type in ('EXPENSE','SETTLEMENT')), hmac varchar(64) not null, primary key (id));
create table balances (created_at timestamp(6) with time zone not null, net_amount_minor bigint not null, updated_at timestamp(6) with time zone not null, version bigint, currency_code uuid not null, group_id uuid not null, id uuid not null, user_id uuid not null, primary key (id), constraint uk_balance_group_user_currency unique (group_id, user_id, currency_code));
create table currencies (code varchar(3) not null unique, decimal_places integer not null, symbol varchar(5) not null, id uuid not null, name varchar(255) not null, primary key (id));
create table expense_payers (amount_paid_minor bigint not null, created_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, version bigint, expense_id uuid not null, id uuid not null, user_id uuid not null, primary key (id), constraint uk_expense_payer_expense_user unique (expense_id, user_id));
create table expense_shares (percentage numeric(7,4), share_weight integer, created_at timestamp(6) with time zone not null, owed_amount_minor bigint not null, updated_at timestamp(6) with time zone not null, version bigint, expense_id uuid not null, id uuid not null, user_id uuid not null, primary key (id), constraint uk_expense_share_expense_user unique (expense_id, user_id));
create table expenses (created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, expense_date timestamp(6) with time zone not null, total_amount_minor bigint not null, updated_at timestamp(6) with time zone not null, version bigint, created_by uuid not null, currency_code uuid not null, group_id uuid, id uuid not null, split_type varchar(20) check (split_type in ('EQUAL','EXACT','PERCENTAGE','SHARES')), description varchar(255) not null, notes varchar(255), primary key (id));
create table group_invite_links (is_active boolean not null, max_uses integer, use_count integer not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, expires_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, version bigint, code varchar(16) not null, created_by uuid not null, group_id uuid not null, id uuid not null, type varchar(20) not null check (type in ('PRIMARY','TEMPORARY')), primary key (id), constraint uk_group_invite_link_code unique (code));
create table group_memberships (active_since timestamp(6) with time zone not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, left_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, version bigint, group_id uuid not null, id uuid not null, user_id uuid not null, role varchar(20) not null check (role in ('ADMIN','MEMBER')), status varchar(20) not null check (status in ('ACTIVE','LEFT','REMOVED')), primary key (id), constraint uk_group_membership_group_user unique (group_id, user_id));
create table groups (member_count integer not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, version bigint, created_by uuid not null, default_currency uuid not null, id uuid not null, type varchar(20) not null check (type in ('HOME','TRIP','COUPLE','OTHER','INDIVIDUAL')), description varchar(255), name varchar(255) not null, preferences jsonb, primary key (id));
create table languages (code varchar(5) not null unique, id uuid not null, name varchar(255) not null, native_name varchar(255) not null, primary key (id));
create table notification_templates (id uuid not null, channel varchar(20) not null, type varchar(50) not null unique, body TEXT not null, subject varchar(255) not null, primary key (id));
create table settlements (app_initiated boolean not null, amount_minor bigint not null, confirmed_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, version bigint, currency_code uuid not null, from_user_id uuid not null, group_id uuid not null, id uuid not null, to_user_id uuid not null, method varchar(20) check (method in ('UPI','CASH','OTHER')), status varchar(20) not null check (status in ('PROPOSED','CONFIRMED','CANCELLED','REJECTED')), note varchar(255), primary key (id));
create table user_profiles (created_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, default_currency uuid not null, id uuid not null, language uuid not null, preferences jsonb, primary key (id));
create table users (email_verified boolean not null, created_at timestamp(6) with time zone not null, deleted_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, version bigint, id uuid not null, auth_provider varchar(20) not null check (auth_provider in ('GOOGLE','APPLE','PASSWORD','REFRESH')), password_hash varchar(100), email varchar(255) not null unique, first_name varchar(255) not null, full_name varchar(255) not null, last_name varchar(255) not null, profile_picture varchar(255), primary key (id));
